  const aliquotaReversa = (impostoPGDAS / faturamentoNumerico) * 100;
  const diferencaAliquotas = Math.abs(aliquotaEfetiva - aliquotaReversa);

  console.log(`Alíquota Efetiva (tabela): ${aliquotaEfetiva.toFixed(2)}%`);
