// ========================================
// FUNÇÃO: CALCULAR RBT12 MÓVEL
// ========================================
function calcularRBT12Movel(mesAlvo, receitasHistoricas) {
    // mesAlvo: "01/2025"
    // receitasHistoricas: array com {mes: "01/2024", valor: "27.550,00"}

    const [mesNum, anoNum] = mesAlvo.split('/').map(Number);

    // ✅ CORRIGIDO: RBT12 = 12 meses ANTERIORES ao mês de apuração (NÃO inclui o próprio mês)
    // Exemplo: para Out/2025, preciso de Out/2024 até Set/2025 (12 meses anteriores)
    // Exemplo: para Jan/2025, preciso de Jan/2024 até Dez/2024 (12 meses anteriores)

    let mesesNecessarios = [];

    // Gerar lista dos 12 meses que compõem o RBT12 (de 12 meses antes até 1 mês antes)
    for (let i = 12; i >= 1; i--) {
        let mes = mesNum - i;
        let ano = anoNum;

        // Ajustar mês e ano
        while (mes <= 0) {
            mes += 12;
            ano -= 1;
        }

        const mesFormatado = String(mes).padStart(2, '0') + '/' + ano;
        mesesNecessarios.push(mesFormatado);
    }

    console.log(`🔍 RBT12 para ${mesAlvo} precisa de:`, mesesNecessarios);

    // Verificar se tem TODOS os 12 meses
    let todosEncontrados = true;
    let soma = 0;

    for (const mesNecessario of mesesNecessarios) {
        const receita = receitasHistoricas.find(r => r.mes === mesNecessario);

        if (!receita) {
            console.warn(`⚠️ Mês ${mesNecessario} NÃO encontrado - impossível calcular RBT12 para ${mesAlvo}`);
            todosEncontrados = false;
            break;
        }

        const valor = parseFloatBR(receita.valor);
        soma += valor;
        console.log(`  ✓ ${mesNecessario}: R$ ${valor.toFixed(2)}`);
    }

    if (!todosEncontrados) {
        return null; // Não foi possível calcular
    }

    console.log(`✅ RBT12 para ${mesAlvo}: R$ ${soma.toFixed(2)}`);
    return soma;
}

// ========================================
// MONTAR ARRAY DE MESES
// ========================================
const mesesNomes = [
    'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
    'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

const mesesProcessados = [];
let totalFaturamento = 0;
let totalImpostos = 0;
let totalFolha = 0;
let totalCompras = 0;
let totalLucro = 0;

// ========================================
// PROCESSAR CADA MÊS DO ANO CORRENTE
// ========================================
// ✅ FILTRAR APENAS MESES DO ANO DA COMPETÊNCIA
const anoCompetencia = periodoAtual ? periodoAtual.split('/')[1] : new Date().getFullYear().toString();
const receitasAnoCorrente = receitasMensais.filter(receita => {
    const anoReceita = receita.mes.split('/')[1];
    return anoReceita === anoCompetencia;
});

console.log(`📅 Ano da competência: ${anoCompetencia}`);
console.log(`📊 Meses filtrados do ano ${anoCompetencia}: ${receitasAnoCorrente.length}`);

receitasAnoCorrente.forEach((receita, index) => {
    // Extrair número do mês (ex: "01/2025" → 1)
    const mesNumero = parseInt(receita.mes.split('/')[0]);
    const mesNome = mesesNomes[mesNumero - 1];

    // Buscar receita
    const faturamento = parseFloatBR(receita.valor);

    // ========================================
    // ✅ CALCULAR IMPOSTOS COM ALÍQUOTA EFETIVA (Receita × Alíquota)
    // ========================================
    let impostos = 0;
    let fonteImposto = 'naoCalculavel';
    let aliquotaMes = 0;

    // Calcular RBT12 móvel para obter a alíquota efetiva
    const rbt12 = calcularRBT12Movel(receita.mes, receitasMensaisHistoricas);

    if (rbt12 !== null && rbt12 > 0) {
        // ✅ CONSEGUIU CALCULAR RBT12 - Usar alíquota efetiva da tabela
        const resultado = calcularAliquotaProgressiva(anexo, rbt12);

        if (resultado && resultado.sucesso) {
            aliquotaMes = resultado.aliquotaEfetiva;
            // ✅ IMPOSTO TEÓRICO = Faturamento × Alíquota Efetiva
            impostos = faturamento * (aliquotaMes / 100);
            fonteImposto = 'calculado';
            console.log(`✅ ${receita.mes}: Alíquota Efetiva = ${aliquotaMes.toFixed(2)}% | RBT12 = R$ ${rbt12.toFixed(2)} | Imposto Teórico = R$ ${impostos.toFixed(2)}`);
        } else {
            console.warn(`⚠️ ${receita.mes}: Erro ao calcular alíquota:`, resultado?.erro);
            impostos = 0;
            aliquotaMes = 0;
        }
    } else {
        // ❌ NÃO CONSEGUIU CALCULAR RBT12 - Tentar usar valor real como fallback
        const impostoReal = impostosMensais.find(imp => imp.mes === receita.mes);

        if (impostoReal) {
            // Fallback: usar valor real do PGDAS (já com retenções descontadas)
            impostos = parseFloatBR(impostoReal.valor);
            fonteImposto = 'real';
            // Calcular alíquota reversa para exibição
            aliquotaMes = faturamento > 0 ? (impostos / faturamento) * 100 : 0;
            console.log(`⚠️ ${receita.mes}: Usando imposto REAL (fallback) = R$ ${impostos.toFixed(2)} (alíquota aprox. ${aliquotaMes.toFixed(2)}%)`);
        } else {
            console.warn(`⚠️ ${receita.mes}: Impossível calcular - falta dados históricos`);
            impostos = 0;
            aliquotaMes = 0;
            fonteImposto = 'naoCalculavel';
        }
    }

    // ========================================
    // ✅ BUSCAR FOLHA (COM FALLBACK PARA MÊS ATUAL)
    // ========================================
    let folha = 0;

    const folhaCorrespondente = folhasMensais.find(f => f.mes === receita.mes);

    if (folhaCorrespondente) {
        folha = parseFloatBR(folhaCorrespondente.valor);
    } else if (receita.mes === periodoAtual) {
        folha = folhaMesAtual;
        console.log(`✓ Folha de ${receita.mes} obtida da seção4_FolhaPagamento: ${folha.toFixed(2)}`);
    } else {
        console.warn(`⚠️ Folha de ${receita.mes} não encontrada`);
        folha = 0;
    }

    // ========================================
    // ✅ BUSCAR COMPRAS DO MÊS (Resumo por Acumulador via AGENTE_4)
    // ========================================
    let compras = 0;

    const compraCorrespondente = comprasMensais.find(c => c.mes === receita.mes);

    if (compraCorrespondente) {
        compras = parseFloatBR(compraCorrespondente.valor);
        console.log(`✅ Compras de ${receita.mes}: R$ ${compras.toFixed(2)} (fonte: ${compraCorrespondente.fonte || 'historico'})`);
    } else {
        console.log(`⏭️ Compras de ${receita.mes}: R$ 0,00 (não encontrado)`);
    }

    // Calcular lucro
    const lucro = faturamento - impostos - folha - compras;

    // Acumular totais
    totalFaturamento += faturamento;
    totalImpostos += impostos;
    totalFolha += folha;
    totalCompras += compras;
    totalLucro += lucro;

    // Adicionar ao array
    mesesProcessados.push({
        mes: mesNome,
        mesOriginal: receita.mes,
        faturamento: {
            valor: faturamento,
            valorFormatado: formatarValorBR(faturamento)
        },
        impostos: {
            valor: impostos,
            valorFormatado: formatarValorBR(impostos),
            aliquota: aliquotaMes.toFixed(2) + '%',
            fonte: fonteImposto  // 'real', 'calculado' ou 'naoCalculavel'
        },
        folha: {
            valor: folha,
            valorFormatado: formatarValorBR(folha),
            fonte: folhaCorrespondente ? 'historico' : (receita.mes === periodoAtual ? 'mesAtual' : 'naoEncontrada')
        },
        compras: {
            valor: compras,
            valorFormatado: formatarValorBR(compras)
        },
        lucro: {
            valor: lucro,
            valorFormatado: formatarValorBR(lucro),
            ehPositivo: lucro >= 0,
            cor: lucro >= 0 ? '#10b981' : '#dc2626'
        }
    });
});

