// ========================================

function parseFloatBR(valor) {
  if (typeof valor === 'number') return valor;
  if (!valor) return 0;
  return parseFloat(valor.toString().replace(/\./g, '').replace(',', '.')) || 0;
}

function formatarAliquota(valor) {
  return valor.toFixed(2).replace('.', ',');
}

// ========================================
// FUNÇÃO PRINCIPAL - CÁLCULO DE ALÍQUOTA
// ========================================

function calcularAliquotaProgressiva(anexo, receitaAcumulada12m) {
  // Validar anexo
  if (!anexo || anexo === null || anexo === '') {
    return {
      sucesso: false,
      aliquotaFormatada: '0,00',
      aliquotaDecimal: 0,
      aliquotaEfetiva: 0,
      faixa: 0,
      erro: 'Anexo não informado'
    };
  }

  // Normalizar anexo
  const anexoNormalizado = anexo.toString().trim().toUpperCase();

  // Verificar se anexo existe
  if (!TABELAS_SIMPLES_NACIONAL[anexoNormalizado]) {
    return {
      sucesso: false,
      aliquotaFormatada: '0,00',
      aliquotaDecimal: 0,
      aliquotaEfetiva: 0,
      faixa: 0,
      erro: `Anexo '${anexo}' inválido. Valores aceitos: I, II, III, IV, V`
    };
  }

  // Converter receita para número
  const rbt12 = parseFloatBR(receitaAcumulada12m);

  // Validar receita
  if (rbt12 <= 0) {
    return {
      sucesso: false,
      aliquotaFormatada: '0,00',
      aliquotaDecimal: 0,
      aliquotaEfetiva: 0,
      faixa: 0,
      erro: 'Receita bruta acumulada deve ser maior que zero'
    };
  }

  // Validar limite máximo do Simples Nacional
  if (rbt12 > 4800000.00) {
    return {
      sucesso: false,
      aliquotaFormatada: '0,00',
      aliquotaDecimal: 0,
      aliquotaEfetiva: 0,
      faixa: 0,
      erro: `Receita de R$ ${rbt12.toLocaleString('pt-BR', {minimumFractionDigits: 2})} excede o limite do Simples Nacional (R$ 4.800.000,00)`
    };
  }

  // Identificar faixa
  const tabela = TABELAS_SIMPLES_NACIONAL[anexoNormalizado];
  let faixaEncontrada = null;

  for (let i = 0; i < tabela.length; i++) {
    if (rbt12 <= tabela[i].limite) {
      faixaEncontrada = tabela[i];
      break;
    }
  }

  if (!faixaEncontrada) {
    faixaEncontrada = tabela[tabela.length - 1];
  }

  // Calcular alíquota efetiva
  // Fórmula: ((RBT12 × Alíquota Nominal) - Dedução) ÷ RBT12
  const aliquotaNominalDecimal = faixaEncontrada.aliquotaNominal / 100;
  const impostoCalculado = (rbt12 * aliquotaNominalDecimal) - faixaEncontrada.deducao;
  const aliquotaEfetiva = (impostoCalculado / rbt12) * 100;

  return {
    sucesso: true,
    aliquotaFormatada: formatarAliquota(aliquotaEfetiva),
    aliquotaDecimal: aliquotaEfetiva / 100,
    aliquotaEfetiva: aliquotaEfetiva, // Em % (10.19)
    faixa: faixaEncontrada.faixa,
    erro: null,
    detalhes: {
      anexo: anexoNormalizado,
      receitaBrutaAcumulada: rbt12,
      faixaNumero: faixaEncontrada.faixa,
      aliquotaNominal: faixaEncontrada.aliquotaNominal,
      deducao: faixaEncontrada.deducao,
      formula: `((${rbt12.toFixed(2)} × ${faixaEncontrada.aliquotaNominal}%) - ${faixaEncontrada.deducao}) ÷ ${rbt12.toFixed(2)} = ${aliquotaEfetiva.toFixed(2)}%`
    }
  };
}

